+  transcriptTimedText,
+  lengthArg,
+}: {
+  slides: SlideTimelineEntry[];
+  transcriptTimedText: string | null | undefined;
+  lengthArg: { kind: "preset"; preset: SummaryLength } | { kind: "chars"; maxCharacters: number };
